        XCTAssertEqual(evidence.downstreamIssueID.rawValue, "GH-700")
        XCTAssertEqual(evidence.runContext.runID, upstreamData.runContext.runID)
        XCTAssertEqual(evidence.runContext.runID, traderEvidence.runContext.runID)
