        let evidence = try ReleaseV040BinanceTestnetModeBoundary().run(upstreamAdapterEvidence: upstreamAdapterEvidence)

        XCTAssertTrue(upstreamAdapterEvidence.evidenceHeld)
        XCTAssertTrue(evidence.evidenceHeld)
