            )
        )
        XCTAssertTrue(databaseTarget.contains("\"ReleaseV030EventStoreRehearsalEvidence.swift\""))

        for forbidden in [
            "import ExecutionClient",
            "import ExecutionEngine",
            "import RiskEngine",
