                shutdownAt: Date(timeIntervalSince1970: 1_704_067_399)
            )
        ) { error in
            XCTAssertEqual(
                error as? CoreError,
                .liveTradingBoundaryForbiddenCapability("traderRuntimeLifecycle.shutdownBeforeStart")
