        let replacedLog = try XCTUnwrap(evidence.eventLogs.first { $0.path == .acceptedReplacedFilled })
        XCTAssertTrue(replacedLog.statesCovered.contains(.replaced))
        XCTAssertEqual(replacedLog.terminalState, .filled)
