    private struct UnsafeConstructOccurrence {
        let relativePath: String
        let lineNumber: Int
        let construct: String
        let line: String
        let context: String

        var description: String {
            "\(relativePath):\(lineNumber): \(construct): \(line.trimmingCharacters(in: .whitespaces))"
        }
    }

